            cells = [c.strip().rstrip("\\").strip() for c in line.split("&")]
            row = "<tr>" + "".join(f"<td>{c}</td>" for c in cells) + "</tr>"
            out_rows.append(row)
        else:
            out_rows.append(line)
    return "\n".join(out_rows)


